import { useState, useEffect } from 'react';
import { DB, apiFetch } from '../data/db';

export default function Products() {
  const [products, setProducts] = useState([...DB.products]);
  const [activeCategory, setActiveCategory] = useState('All');
  const [search, setSearch] = useState('');
  const [adminMode, setAdminMode] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [form, setForm] = useState({ name: '', category: '', description: '', partNumber: '', inStock: true, image: '' });
  const [msg, setMsg] = useState('');
  const [msgType, setMsgType] = useState('');

  useEffect(() => {
    document.title = 'Products - Gursons India';
    window.scrollTo(0, 0);
    loadProducts();
  }, []);

  async function loadProducts() {
    const res = await apiFetch('/products');
    if (res?.data) setProducts(res.data);
  }

  const categories = ['All', ...new Set(products.map(p => p.category))];

  const filtered = products.filter(p => {
    const matchCat = activeCategory === 'All' || p.category === activeCategory;
    const matchSearch = !search ||
      p.name.toLowerCase().includes(search.toLowerCase()) ||
      p.description.toLowerCase().includes(search.toLowerCase()) ||
      p.partNumber.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  function flashMsg(text, type) {
    setMsg(text); setMsgType(type);
    setTimeout(() => setMsg(''), 3500);
  }

  function resetForm() {
    setForm({ name: '', category: '', description: '', partNumber: '', inStock: true, image: '' });
    setEditingProduct(null);
    setShowForm(false);
  }

  async function handleSubmit() {
    if (!form.name || !form.category) { flashMsg('Name and category are required.', 'error'); return; }
    if (editingProduct) {
      const res = await apiFetch(`/products/${editingProduct.id}`, { method: 'PUT', body: JSON.stringify(form) });
      if (res?.data) {
        setProducts(ps => ps.map(p => p.id === editingProduct.id ? res.data : p));
      } else {
        setProducts(ps => ps.map(p => p.id === editingProduct.id ? { ...p, ...form } : p));
        DB.products = DB.products.map(p => p.id === editingProduct.id ? { ...p, ...form } : p);
      }
      flashMsg('Product updated successfully!', 'success');
    } else {
      const res = await apiFetch('/products', { method: 'POST', body: JSON.stringify(form) });
      if (res?.data) {
        setProducts(ps => [...ps, res.data]);
      } else {
        const newProd = { id: DB.nextId++, ...form };
        DB.products.push(newProd);
        setProducts([...DB.products]);
      }
      flashMsg('Product added successfully!', 'success');
    }
    resetForm();
  }

  async function handleDelete(id) {
    if (!window.confirm('Delete this product?')) return;
    await apiFetch(`/products/${id}`, { method: 'DELETE' });
    setProducts(ps => ps.filter(p => p.id !== id));
    DB.products = DB.products.filter(p => p.id !== id);
    flashMsg('Product deleted.', 'success');
  }

  function openEdit(p) {
    setEditingProduct(p);
    setForm({ name: p.name, category: p.category, description: p.description, partNumber: p.partNumber, inStock: p.inStock, image: p.image || '' });
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  const inputStyle = {
    width: '100%', background: 'rgba(255,255,255,0.08)',
    border: '1px solid rgba(255,255,255,0.15)', color: '#fff',
    padding: '11px 14px', fontSize: 14, fontFamily: 'var(--font-body)',
    outline: 'none', borderRadius: 6, transition: 'border 0.2s',
  };

  return (
    <div className="page-enter" style={{ paddingTop: 70 }}>

      {/* HERO */}
      <section style={{
        padding: '100px 0 60px',
        background: 'linear-gradient(135deg, var(--navy) 0%, var(--navy-mid) 100%)',
        position: 'relative', overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', inset: 0,
          backgroundImage: 'linear-gradient(rgba(255,255,255,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.025) 1px, transparent 1px)',
          backgroundSize: '60px 60px',
        }} />
        <div className="container" style={{ position: 'relative', zIndex: 1 }}>
          <div className="eyebrow animate-fadeUp delay-1">Product Catalog</div>
          <h1 className="animate-fadeUp delay-2" style={{ fontFamily: 'var(--font-head)', fontSize: 'clamp(3rem, 7vw, 6rem)', fontWeight: 800, lineHeight: 1, letterSpacing: -2 }}>
            OUR<br /><span style={{ color: 'var(--gold)' }}>PRODUCTS</span>
          </h1>
          <p className="animate-fadeUp delay-3" style={{ color: 'var(--white-70)', fontSize: 16, marginTop: '1rem', maxWidth: 480 }}>
            Browse our extensive catalog of broadcast equipment, Harris spares, NATUEL products,
            and electronic components.
          </p>
        </div>
      </section>

      {/* MAIN */}
      <section className="section">
        <div className="container">

          {/* Admin bar */}
          <div style={{
            display: 'flex', alignItems: 'center', gap: '1rem',
            background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
            borderRadius: 8, padding: '12px 20px', marginBottom: '2rem', flexWrap: 'wrap',
          }}>
            <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'var(--gold)' }}>Admin Mode</span>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}>
              <div style={{
                width: 44, height: 24, borderRadius: 12, background: adminMode ? 'var(--gold)' : 'rgba(255,255,255,0.2)',
                position: 'relative', transition: 'background 0.3s', cursor: 'pointer',
              }} onClick={() => { setAdminMode(m => !m); setShowForm(false); }}>
                <div style={{
                  position: 'absolute', top: 2, left: adminMode ? 22 : 2,
                  width: 20, height: 20, borderRadius: '50%', background: '#fff',
                  transition: 'left 0.3s', boxShadow: '0 1px 4px rgba(0,0,0,0.3)',
                }} />
              </div>
              <span style={{ fontSize: 13, color: 'var(--white-70)' }}>
                {adminMode ? 'Admin enabled — add, edit, delete products' : 'Toggle to manage products'}
              </span>
            </label>
            {adminMode && (
              <button className="btn btn-gold btn-sm" style={{ marginLeft: 'auto' }}
                onClick={() => { setShowForm(s => !s); setEditingProduct(null); setForm({ name: '', category: '', description: '', partNumber: '', inStock: true }); }}>
                {showForm ? '✕ Cancel' : '+ Add Product'}
              </button>
            )}
          </div>

          {/* Add/Edit Form */}
          {showForm && adminMode && (
            <div style={{
              background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)',
              borderRadius: 12, padding: '2rem', marginBottom: '2rem',
              animation: 'fadeUp 0.3s ease forwards',
            }}>
              <div style={{ fontFamily: 'var(--font-head)', fontSize: 22, fontWeight: 700, color: 'var(--gold)', marginBottom: '1.5rem' }}>
                {editingProduct ? 'Edit Product' : 'Add New Product'}
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem' }}>
                {[
                  { id: 'name', label: 'Product Name *', type: 'text', ph: 'e.g. Harris PCB Board' },
                  { id: 'partNumber', label: 'Part Number', type: 'text', ph: 'e.g. HRS-001' },
                ].map(f => (
                  <div key={f.id}>
                    <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>{f.label}</label>
                    <input style={inputStyle} value={form[f.id]} placeholder={f.ph}
                      onChange={e => setForm(fm => ({ ...fm, [f.id]: e.target.value }))}
                      onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                      onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.15)'}
                    />
                  </div>
                ))}
                <div>
                  <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>Category *</label>
                  <select style={{ ...inputStyle, cursor: 'pointer' }} value={form.category}
                    onChange={e => setForm(fm => ({ ...fm, category: e.target.value }))}>
                    <option value="">Select category</option>
                    {['Harris Spares', 'NATUEL', 'Broadcast Equipment', 'HVAC'].map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>Availability</label>
                  <select style={{ ...inputStyle, cursor: 'pointer' }} value={form.inStock.toString()}
                    onChange={e => setForm(fm => ({ ...fm, inStock: e.target.value === 'true' }))}>
                    <option value="true">In Stock</option>
                    <option value="false">Out of Stock</option>
                  </select>
                </div>
              </div>
              <div style={{ marginTop: '1rem' }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>Description</label>
                <textarea style={{ ...inputStyle, resize: 'vertical', minHeight: 90 }} value={form.description}
                  placeholder="Product description..."
                  onChange={e => setForm(fm => ({ ...fm, description: e.target.value }))}
                  onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.15)'}
                />
              </div>

              {/* ── IMAGE FIELD ── */}
              <div style={{ marginTop: '1rem' }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>
                  Image URL or Path
                </label>
                <input style={inputStyle} value={form.image}
                  placeholder="e.g. /images/my-product.jpg  or  https://example.com/photo.jpg"
                  onChange={e => setForm(fm => ({ ...fm, image: e.target.value }))}
                  onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.15)'}
                />
                <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.35)', marginTop: 6 }}>
                  💡 To use a local image: copy the file into <code style={{ color: 'var(--gold)' }}>frontend/public/images/</code> then enter <code style={{ color: 'var(--gold)' }}>/images/filename.jpg</code>
                </div>
                {/* Live preview */}
                {form.image && (
                  <div style={{ marginTop: 10, display: 'flex', alignItems: 'center', gap: 12 }}>
                    <img
                      src={form.image}
                      alt="Preview"
                      style={{ width: 80, height: 60, objectFit: 'cover', borderRadius: 6, border: '1px solid rgba(255,255,255,0.15)' }}
                      onError={e => { e.target.style.display = 'none'; }}
                    />
                    <span style={{ fontSize: 12, color: 'rgba(255,255,255,0.4)' }}>Image preview</span>
                  </div>
                )}
              </div>
              <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                <button className="btn btn-primary" onClick={handleSubmit}>{editingProduct ? 'Save Changes' : 'Add Product'}</button>
                <button className="btn btn-outline" onClick={resetForm}>Cancel</button>
              </div>
              {msg && (
                <div style={{
                  marginTop: '1rem', padding: '10px 16px', borderRadius: 6,
                  background: msgType === 'success' ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)',
                  color: msgType === 'success' ? '#22C55E' : '#EF4444',
                  border: `1px solid ${msgType === 'success' ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)'}`,
                  fontSize: 13,
                }}>
                  {msg}
                </div>
              )}
            </div>
          )}

          {/* Filters & Search */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '1rem', marginBottom: '2rem' }}>
            <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', alignItems: 'center' }}>
              {categories.map(c => (
                <button key={c}
                  onClick={() => setActiveCategory(c)}
                  style={{
                    padding: '7px 18px', fontSize: 12, fontWeight: 600,
                    letterSpacing: 1, textTransform: 'uppercase', cursor: 'pointer',
                    border: '1px solid',
                    borderColor: activeCategory === c ? 'var(--gold)' : 'rgba(255,255,255,0.2)',
                    background: activeCategory === c ? 'var(--gold)' : 'transparent',
                    color: activeCategory === c ? 'var(--navy)' : 'rgba(255,255,255,0.7)',
                    borderRadius: 4, transition: 'all 0.2s', fontFamily: 'var(--font-body)',
                  }}>
                  {c}
                </button>
              ))}
              <span style={{ fontSize: 13, color: 'var(--white-30)' }}>{filtered.length} item{filtered.length !== 1 ? 's' : ''}</span>
            </div>
            <input
              style={{
                background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)',
                color: '#fff', padding: '9px 16px', fontSize: 13, borderRadius: 6,
                outline: 'none', width: 240, fontFamily: 'var(--font-body)',
              }}
              placeholder="Search products..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              onFocus={e => e.target.style.borderColor = 'var(--gold)'}
              onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.15)'}
            />
          </div>

          {/* Products Grid */}
          {filtered.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--white-30)', fontSize: 16 }}>
              No products found. Try a different filter or search term.
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
              {filtered.map((p, i) => (
                <div key={p.id} className="product-card" style={{ animationDelay: `${i * 0.05}s`, padding: 0, overflow: 'hidden' }}>

                  {/* ── PRODUCT IMAGE ── */}
                  {p.image ? (
                    <img
                      src={p.image}
                      alt={p.name}
                      style={{ width: '100%', height: 180, objectFit: 'cover', display: 'block' }}
                      onError={e => {
                        // If image fails to load, replace with placeholder
                        e.target.style.display = 'none';
                        e.target.nextSibling.style.display = 'flex';
                      }}
                    />
                  ) : null}
                  {/* Fallback placeholder shown when no image or image fails */}
                  <div style={{
                    width: '100%', height: 180,
                    background: 'linear-gradient(135deg, rgba(201,168,76,0.08), rgba(255,255,255,0.04))',
                    display: p.image ? 'none' : 'flex',
                    alignItems: 'center', justifyContent: 'center', flexDirection: 'column',
                    gap: 8, borderBottom: '1px solid rgba(255,255,255,0.07)',
                  }}>
                    <div style={{ fontSize: 36, opacity: 0.3 }}>📦</div>
                    <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.2)', letterSpacing: 2, textTransform: 'uppercase' }}>No Image</div>
                  </div>

                  {/* Card body */}
                  <div style={{ padding: '1.25rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                      <span style={{ fontSize: 10, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'var(--gold)' }}>{p.category}</span>
                      <span className={`badge ${p.inStock ? 'badge-green' : 'badge-red'}`}>
                        {p.inStock ? 'In Stock' : 'Out of Stock'}
                      </span>
                    </div>
                    <h3 style={{ fontFamily: 'var(--font-head)', fontSize: 20, fontWeight: 700, marginBottom: '0.5rem', letterSpacing: -0.5 }}>{p.name}</h3>
                    <p style={{ fontSize: 13, color: 'var(--white-70)', lineHeight: 1.6, marginBottom: '1rem' }}>{p.description}</p>
                    <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.3)', fontFamily: 'monospace', letterSpacing: 1 }}>
                      PN: {p.partNumber || '—'}
                    </div>
                    {adminMode && (
                      <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
                        <button onClick={() => openEdit(p)}
                          style={{ padding: '6px 14px', fontSize: 11, fontWeight: 600, letterSpacing: 1, textTransform: 'uppercase', cursor: 'pointer', background: 'transparent', border: '1px solid rgba(255,255,255,0.2)', color: 'rgba(255,255,255,0.7)', borderRadius: 4, transition: 'all 0.2s', fontFamily: 'var(--font-body)' }}
                          onMouseEnter={e => { e.target.style.borderColor = '#fff'; e.target.style.color = '#fff'; }}
                          onMouseLeave={e => { e.target.style.borderColor = 'rgba(255,255,255,0.2)'; e.target.style.color = 'rgba(255,255,255,0.7)'; }}>
                          Edit
                        </button>
                        <button onClick={() => handleDelete(p.id)}
                          style={{ padding: '6px 14px', fontSize: 11, fontWeight: 600, letterSpacing: 1, textTransform: 'uppercase', cursor: 'pointer', background: 'transparent', border: '1px solid rgba(239,68,68,0.3)', color: '#EF4444', borderRadius: 4, transition: 'all 0.2s', fontFamily: 'var(--font-body)' }}
                          onMouseEnter={e => e.target.style.background = 'rgba(239,68,68,0.1)'}
                          onMouseLeave={e => e.target.style.background = 'transparent'}>
                          Delete
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
}
